<?php session_start(); require '../scripts/database.php'; require '../includes/auth.php'; requireLogin(); requireRole('Admin'); $user_id = $_SESSION['user_id']; ?> <!DOCTYPE html> <html lang="fr"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title>Dashboard Admin</title> <script src="https://cdn.tailwindcss.com"></script> </head> <body class="bg-gray-100"> <div class="flex"> <!-- SIDEBAR --> <aside class="w-64 bg-blue-700 text-white min-h-screen p-5 fixed"> <h2 class="text-xl font-bold mb-6">Admin Dashboard</h2> <nav class="space-y-3 text-sm"> <a href="#stats" class="nav-link block p-2 rounded hover:bg-blue-600">Statistiques</a> <a href="#users" class="nav-link block p-2 rounded hover:bg-blue-600">Utilisateurs</a> <a href="#classes" class="nav-link block p-2 rounded hover:bg-blue-600">Classes</a> <a href="#courses" class="nav-link block p-2 rounded hover:bg-blue-600">Cours</a> <a href="#enrollments" class="nav-link block p-2 rounded hover:bg-blue-600">Inscriptions</a> </nav> </aside> <!-- MAIN --> <main class="ml-64 flex-1 p-6 space-y-10"> <h1 class="text-2xl font-bold">Dashboard Administrateur</h1> <p class="text-gray-500">Gestion globale de la plateforme</p> <?php // ===================== STATS ===================== $totalStudents = $conn->query(" SELECT COUNT(*) FROM students ")->fetchColumn(); $totalProfessors = $conn->query(" SELECT COUNT(*) FROM users WHERE role_id = (SELECT id FROM roles WHERE label='Prof') ")->fetchColumn(); $totalCourses = $conn->query("SELECT COUNT(*) FROM courses")->fetchColumn(); $totalClasses = $conn->query("SELECT COUNT(*) FROM classes")->fetchColumn(); $studentsPerClass = $conn->query(" SELECT c.name, COUNT(s.id) as total FROM classes c LEFT JOIN students s ON s.class_id = c.id GROUP BY c.id, c.name ")->fetchAll(PDO::FETCH_ASSOC); ?> <!-- STATS --> <section id="stats" class="grid grid-cols-1 md:grid-cols-4 gap-4"> <div class="bg-white p-4 rounded shadow"> <p>Étudiants</p> <h2 class="text-xl font-bold"><?= $totalStudents ?></h2> </div> <div class="bg-white p-4 rounded shadow"> <p>Professeurs</p> <h2 class="text-xl font-bold"><?= $totalProfessors ?></h2> </div> <div class="bg-white p-4 rounded shadow"> <p>Cours</p> <h2 class="text-xl font-bold"><?= $totalCourses ?></h2> </div> <div class="bg-white p-4 rounded shadow"> <p>Classes</p> <h2 class="text-xl font-bold"><?= $totalClasses ?></h2> </div> </section> <!-- USERS --> <section id="users" class="bg-white p-5 rounded shadow"> <h2 class="font-bold mb-4">Utilisateurs</h2> <?php $users = $conn->query(" SELECT u.id, u.firstname, u.lastname, u.email, r.label, u.role_id FROM users u LEFT JOIN roles r ON u.role_id = r.id ")->fetchAll(PDO::FETCH_ASSOC); ?> <table class="w-full text-sm"> <thead class="bg-gray-100"> <tr> <th class="p-2">Nom</th> <th class="p-2">Email</th> <th class="p-2">Rôle</th> </tr> </thead> <tbody> <?php foreach ($users as $u): ?> <tr class="border-t"> <td class="p-2"><?= htmlspecialchars($u['firstname'].' '.$u['lastname']) ?></td> <td class="p-2"><?= htmlspecialchars($u['email']) ?></td> <td class="p-2"><?= htmlspecialchars($u['label']) ?></td> </tr> <?php endforeach; ?> </tbody> </table> </section> <!-- CLASSES --> <section id="classes" class="bg-white p-5 rounded shadow"> <h2 class="font-bold mb-4">Classes</h2> <?php $classes = $conn->query("SELECT * FROM classes")->fetchAll(PDO::FETCH_ASSOC); ?> <table class="w-full text-sm"> <thead class="bg-gray-100"> <tr> <th>ID</th> <th>Nom</th> <th>Salle</th> </tr> </thead> <tbody> <?php foreach ($classes as $c): ?> <tr class="border-t"> <td class="p-2"><?= $c['id'] ?></td> <td class="p-2"><?= htmlspecialchars($c['name']) ?></td> <td class="p-2"><?= htmlspecialchars($c['classroom_number']) ?></td> </tr> <?php endforeach; ?> </tbody> </table> </section> <!-- COURSES --> <section id="courses" class="bg-white p-5 rounded shadow"> <h2 class="font-bold mb-4">Cours</h2> <?php $courses = $conn->query(" SELECT c.id, c.title, c.description, c.total_hours, u.firstname, u.lastname FROM courses c LEFT JOIN users u ON c.user_id = u.id ")->fetchAll(PDO::FETCH_ASSOC); ?> <table class="w-full text-sm"> <thead class="bg-gray-100"> <tr> <th>Titre</th> <th>Description</th> <th>Heures</th> <th>Professeur</th> </tr> </thead> <tbody> <?php foreach ($courses as $c): ?> <tr class="border-t"> <td class="p-2"><?= htmlspecialchars($c['title']) ?></td> <td class="p-2"><?= htmlspecialchars($c['description']) ?></td> <td class="p-2"><?= $c['total_hours'] ?></td> <td class="p-2"><?= htmlspecialchars($c['firstname'].' '.$c['lastname']) ?></td> </tr> <?php endforeach; ?> </tbody> </table> </section> <!-- ENROLLMENTS --> <section id="enrollments" class="bg-white p-5 rounded shadow"> <h2 class="font-bold mb-4">Inscriptions</h2> <?php $enrollments = $conn->query(" SELECT e.id, e.status, e.enrolled_at, s.student_number, u.firstname, u.lastname, c.title FROM enrollments e JOIN students s ON e.student_id = s.id JOIN users u ON s.user_id = u.id JOIN courses c ON e.course_id = c.id ")->fetchAll(PDO::FETCH_ASSOC); ?> <table class="w-full text-sm"> <thead class="bg-gray-100"> <tr> <th>Étudiant</th> <th>Numéro</th> <th>Cours</th> <th>Date</th> <th>Statut</th> </tr> </thead> <tbody> <?php foreach ($enrollments as $e): ?> <tr class="border-t"> <td class="p-2"><?= htmlspecialchars($e['firstname'].' '.$e['lastname']) ?></td> <td class="p-2"><?= htmlspecialchars($e['student_number']) ?></td> <td class="p-2"><?= htmlspecialchars($e['title']) ?></td> <td class="p-2"><?= $e['enrolled_at'] ?></td> <td class="p-2"><?= $e['status'] ?></td> </tr> <?php endforeach; ?> </tbody> </table> </section> </main> </div> </body> </html>